import { useState, useEffect } from 'react'
import { useNavigate } from 'react-router-dom'
import { useAuth } from '../context/AuthContext'

const HERO = 'data:image/jpeg;base64,'

const WORDS = ['Discipline.', 'Accountability.', 'Personal ownership.']

const styles = `
  @import url('https://fonts.googleapis.com/css2?family=EB+Garamond:ital@0;1&display=swap');

  @keyframes fadeInUp {
    from { opacity: 0; transform: translateY(16px); }
    to   { opacity: 1; transform: translateY(0); }
  }
  @keyframes fadeOutUp {
    from { opacity: 1; transform: translateY(0); }
    to   { opacity: 0; transform: translateY(-14px); }
  }
  @keyframes shimmer {
    0%,100% { opacity: 0.4; }
    50%      { opacity: 0.65; }
  }
  @keyframes scanline {
    0%   { transform: translateY(-100%); }
    100% { transform: translateY(100vh); }
  }
  @keyframes borderGlow {
    0%,100% { box-shadow: 0 0 18px rgba(255,255,255,0.07), 0 0 40px rgba(255,255,255,0.03), inset 0 0 20px rgba(255,255,255,0.02); border-color: rgba(255,255,255,0.13); }
    50%     { box-shadow: 0 0 28px rgba(255,255,255,0.13), 0 0 70px rgba(255,255,255,0.06), inset 0 0 30px rgba(255,255,255,0.04); border-color: rgba(255,255,255,0.28); }
  }
  @keyframes inputPulse {
    0%,100% { box-shadow: 0 0 0px rgba(255,255,255,0); }
    50%     { box-shadow: 0 0 12px rgba(255,255,255,0.08); }
  }

  .word-in  { animation: fadeInUp 0.9s cubic-bezier(0.22,1,0.36,1) forwards; }
  .word-out { animation: fadeOutUp 0.6s cubic-bezier(0.22,1,0.36,1) forwards; }

  .login-card {
    animation: borderGlow 4s ease-in-out infinite;
  }

  .login-input {
    width: 100%;
    box-sizing: border-box;
    background: rgba(255,255,255,0.04);
    border: 1px solid rgba(255,255,255,0.14);
    border-radius: 2px;
    color: white;
    padding: 13px 14px;
    font-size: 1rem;
    font-family: 'Helvetica Neue', Helvetica, sans-serif;
    outline: none;
    -webkit-appearance: none;
    transition: border-color 0.3s, box-shadow 0.3s;
    caret-color: white;
  }
  .login-input:focus {
    border-color: rgba(255,255,255,0.6);
    box-shadow: 0 0 0 1px rgba(255,255,255,0.08), 0 0 20px rgba(255,255,255,0.1), 0 0 40px rgba(255,255,255,0.04);
    animation: inputPulse 2s ease-in-out infinite;
    background: rgba(255,255,255,0.07);
  }

  .enter-btn {
    width: 100%;
    background: white;
    color: black;
    border: none;
    border-radius: 2px;
    padding: 14px;
    font-size: 0.72rem;
    font-weight: 800;
    letter-spacing: 0.3em;
    text-transform: uppercase;
    cursor: pointer;
    font-family: 'Helvetica Neue', Helvetica, sans-serif;
    transition: opacity 0.2s, transform 0.15s, box-shadow 0.2s;
    -webkit-appearance: none;
  }
  .enter-btn:hover  { opacity: 0.92; transform: translateY(-1px); box-shadow: 0 0 24px rgba(255,255,255,0.3), 0 4px 20px rgba(0,0,0,0.4); }
  .enter-btn:active { transform: translateY(0); box-shadow: none; }
  .enter-btn:disabled { opacity: 0.45; cursor: not-allowed; }
`

export default function Login() {
  const { signIn } = useAuth()
  const navigate = useNavigate()
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [error, setError] = useState(null)
  const [loading, setLoading] = useState(false)
  const [wordIndex, setWordIndex] = useState(0)
  const [phase, setPhase] = useState('in')

  useEffect(() => {
    const cycle = () => {
      setPhase('out')
      setTimeout(() => {
        setWordIndex(i => (i + 1) % WORDS.length)
        setPhase('in')
      }, 700)
    }
    const interval = setInterval(cycle, 7000)
    return () => clearInterval(interval)
  }, [])

  const handleSubmit = async (e) => {
    e.preventDefault()
    setLoading(true)
    setError(null)
    const { error } = await signIn(email, password)
    if (error) {
      setError(error.message)
      setLoading(false)
    } else {
      navigate('/dashboard')
    }
  }

  return (
    <>
      <style>{styles}</style>
      <div style={{ minHeight: '100dvh', background: '#000', display: 'flex', alignItems: 'center', justifyContent: 'center', overflow: 'hidden', position: 'relative' }}>

        {/* Hero — fills screen, anchored to show chest/abs on all devices */}
        <div style={{
          position: 'fixed', inset: 0, zIndex: 0,
          backgroundImage: `url('${HERO}')`,
          backgroundSize: 'cover',
          backgroundPosition: '50% 30%',
          backgroundRepeat: 'no-repeat',
          filter: 'contrast(1.25) brightness(1.08) saturate(1.1)',
        }} />

        {/* Radial vignette — edges dark, center open so physique shows */}
        <div style={{
          position: 'fixed', inset: 0, zIndex: 1,
          background: 'radial-gradient(ellipse at 50% 30%, rgba(0,0,0,0.0) 0%, rgba(0,0,0,0.38) 55%, rgba(0,0,0,0.88) 100%)',
        }} />

        {/* Bottom fade */}
        <div style={{
          position: 'fixed', bottom: 0, left: 0, right: 0, height: '40%', zIndex: 2,
          background: 'linear-gradient(to top, rgba(0,0,0,0.45) 0%, rgba(0,0,0,0.15) 40%, rgba(0,0,0,0) 100%)',
        }} />

        {/* Top fade */}
        <div style={{
          position: 'fixed', top: 0, left: 0, right: 0, height: '25%', zIndex: 2,
          background: 'linear-gradient(to bottom, rgba(0,0,0,0.75) 0%, rgba(0,0,0,0) 100%)',
        }} />

        {/* Atmospheric shimmer */}
        <div style={{
          position: 'fixed', inset: 0, zIndex: 2,
          background: 'radial-gradient(ellipse at 50% 30%, rgba(255,255,255,0.07) 0%, rgba(255,255,255,0.02) 40%, transparent 70%)',
          animation: 'shimmer 7s ease-in-out infinite',
        }} />

        {/* Scanline sweep */}
        <div style={{
          position: 'fixed', top: 0, left: 0, right: 0, height: '3px', zIndex: 3,
          background: 'linear-gradient(to bottom, transparent, rgba(255,255,255,0.04), transparent)',
          animation: 'scanline 10s linear infinite',
          pointerEvents: 'none',
        }} />

        {/* Content */}
        <div style={{
          position: 'relative', zIndex: 10,
          display: 'flex', flexDirection: 'column', alignItems: 'center',
          width: '100%', maxWidth: '420px',
          padding: '2rem 1.25rem',
          margin: '0 auto',
        }}>

          {/* Brand */}
          <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', marginBottom: '1.5rem' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '8px' }}>
              <svg width="38" height="32" viewBox="0 0 46 38" fill="none">
                <polygon points="0,36 16,2 22,14 9,36" fill="white"/>
                <polygon points="13,36 26,8 32,22 20,36" fill="white" opacity="0.62"/>
                <polygon points="20,36 30,18 34,28 22,36" fill="white" opacity="0.32"/>
              </svg>
              <div style={{ width: '1px', height: '38px', background: 'rgba(255,255,255,0.35)' }} />
              <span style={{
                color: 'white', fontWeight: 900,
                fontSize: 'clamp(1.8rem, 8vw, 2.8rem)',
                letterSpacing: '0.18em', textTransform: 'uppercase',
                lineHeight: 1, fontFamily: '"Helvetica Neue", Helvetica, sans-serif',
                textShadow: '0 0 40px rgba(255,255,255,0.12)',
              }}>AXIOS</span>
            </div>
            <p style={{ color: 'rgba(255,255,255,0.4)', fontSize: '0.6rem', letterSpacing: '0.42em', textTransform: 'uppercase', fontFamily: '"Helvetica Neue", Helvetica, sans-serif' }}>
              I Am Worthy
            </p>
          </div>

          {/* Animated word */}
          <div style={{ textAlign: 'center', marginBottom: '2rem', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '6px' }}>
            <p style={{ color: 'rgba(255,255,255,0.25)', fontSize: '0.58rem', letterSpacing: '0.28em', textTransform: 'uppercase', fontFamily: '"Helvetica Neue", Helvetica, sans-serif', margin: 0 }}>
              Est. 1989
            </p>
            <div style={{ overflow: 'hidden', height: '2.2rem', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
              <p
                key={wordIndex}
                className={phase === 'in' ? 'word-in' : 'word-out'}
                style={{
                  color: 'rgba(255,255,255,0.8)',
                  fontSize: 'clamp(1rem, 4vw, 1.2rem)',
                  fontFamily: '"EB Garamond", Georgia, serif',
                  fontStyle: 'italic',
                  letterSpacing: '0.04em',
                  margin: 0,
                  textShadow: '0 2px 20px rgba(255,255,255,0.2)',
                }}
              >
                {WORDS[wordIndex]}
              </p>
            </div>
            {/* Progress dots */}
            <div style={{ display: 'flex', gap: '6px', marginTop: '2px' }}>
              {WORDS.map((_, i) => (
                <div key={i} style={{
                  width: i === wordIndex ? '16px' : '4px',
                  height: '2px',
                  borderRadius: '1px',
                  background: i === wordIndex ? 'rgba(255,255,255,0.7)' : 'rgba(255,255,255,0.2)',
                  transition: 'all 0.5s ease',
                }} />
              ))}
            </div>
          </div>

          {/* Form */}
          <form onSubmit={handleSubmit} style={{
            width: '100%',
            background: 'rgba(6,6,6,0.82)',
            border: '1px solid rgba(255,255,255,0.13)',
            borderRadius: '2px',
            padding: 'clamp(1.25rem, 5vw, 2rem)',
            backdropFilter: 'blur(24px)',
            WebkitBackdropFilter: 'blur(24px)',
            boxShadow: '0 8px 60px rgba(0,0,0,0.7), inset 0 0 0 0.5px rgba(255,255,255,0.04)',
          }}>
            <p style={{ color: 'rgba(255,255,255,0.22)', fontSize: '0.58rem', letterSpacing: '0.3em', textTransform: 'uppercase', marginBottom: '1.25rem', textAlign: 'center', fontFamily: '"Helvetica Neue", Helvetica, sans-serif', letterSpacing: '0.38em', color: 'rgba(255,255,255,0.9)', textShadow: '0 0 12px rgba(255,255,255,0.6), 0 0 30px rgba(255,255,255,0.25), 0 0 60px rgba(255,255,255,0.1)' }}>
              Secure Access
            </p>

            <div style={{ marginBottom: '1rem' }}>
              <label style={{ display: 'block', color: 'rgba(255,255,255,0.3)', fontSize: '0.58rem', letterSpacing: '0.22em', textTransform: 'uppercase', marginBottom: '6px', fontFamily: '"Helvetica Neue", Helvetica, sans-serif' }}>Email</label>
              <input
                type="email"
                value={email}
                onChange={e => setEmail(e.target.value)}
                placeholder=""
                autoComplete="off"
                required
                className="login-input"
              />
            </div>

            <div style={{ marginBottom: '1.5rem' }}>
              <label style={{ display: 'block', color: 'rgba(255,255,255,0.3)', fontSize: '0.58rem', letterSpacing: '0.22em', textTransform: 'uppercase', marginBottom: '6px', fontFamily: '"Helvetica Neue", Helvetica, sans-serif' }}>Password</label>
              <input
                type="password"
                value={password}
                onChange={e => setPassword(e.target.value)}
                placeholder=""
                autoComplete="current-password"
                required
                className="login-input"
              />
            </div>

            {error && (
              <p style={{ color: 'rgba(255,100,100,0.85)', fontSize: '0.75rem', marginBottom: '1rem', textAlign: 'center', fontFamily: '"Helvetica Neue", Helvetica, sans-serif' }}>{error}</p>
            )}

            <button type="submit" disabled={loading} className="enter-btn">
              {loading ? 'Entering...' : 'Enter'}
            </button>

            <p style={{ color: 'rgba(255,255,255,0.12)', fontSize: '0.56rem', letterSpacing: '0.15em', textTransform: 'uppercase', textAlign: 'center', marginTop: '1rem', fontFamily: '"Helvetica Neue", Helvetica, sans-serif', letterSpacing: '0.22em', color: 'rgba(255,255,255,0.85)', textShadow: '0 0 10px rgba(255,255,255,0.55), 0 0 25px rgba(255,255,255,0.2), 0 0 50px rgba(255,255,255,0.08)' }}>
              Authorized access only
            </p>
          </form>

          <p style={{ color: 'rgba(255,255,255,0.15)', fontSize: '0.55rem', letterSpacing: '0.15em', textTransform: 'uppercase', marginTop: '1.5rem', fontFamily: '"Helvetica Neue", Helvetica, sans-serif' }}>
            "Axios" — I am worthy
          </p>
        </div>

        <p style={{
          position: 'fixed', bottom: '1.5rem', left: '1.5rem',
          color: 'rgba(255,255,255,0.15)', fontSize: '0.55rem',
          letterSpacing: '0.22em', textTransform: 'uppercase',
          fontStyle: 'italic', zIndex: 10,
          fontFamily: '"Helvetica Neue", Helvetica, sans-serif',
        }}>Est 1989</p>

      </div>
    </>
  )
}
